import React, { useState, useMemo, useEffect } from "react";
import { supabase } from "../lib/supabase.js";
import { motion, AnimatePresence } from "framer-motion";
import { useNavigate } from "react-router-dom";

import Profile from "../components/profile.jsx";
import Settings from "../components/settings.jsx";

const RN_LOGO = "data:image/jpeg;base64,";

export default function Sidebar({
  sessions = [],
  activeChat,
  setActiveChat,
  createNewChat,
  user,
  workspace,
  role,
  subscription,
  refreshSessions,
}) {
  const [search, setSearch] = useState("");
  const [collapsed, setCollapsed] = useState(false);
  const [accountOpen, setAccountOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);

  const [profile, setProfile] = useState(null);
  const [profileLoading, setProfileLoading] = useState(true);

  const navigate = useNavigate();

  /* ESC CLOSE */
  useEffect(() => {
    const handleEsc = (e) => {
      if (e.key === "Escape") {
        setProfileOpen(false);
        setAccountOpen(false);
      }
    };

    window.addEventListener("keydown", handleEsc);
    return () => window.removeEventListener("keydown", handleEsc);
  }, []);

  /* LIVE PROFILE */
  useEffect(() => {
    if (!user?.id) return;

    const loadProfile = async () => {
      setProfileLoading(true);

      const { data } = await supabase
        .from("profiles")
        .select("*")
        .eq("id", user.id)
        .maybeSingle();

      setProfile(data || null);
      setProfileLoading(false);
    };

    loadProfile();

    const channel = supabase
      .channel("profile-live")
      .on(
        "postgres_changes",
        {
          event: "*",
          schema: "public",
          table: "profiles",
          filter: `id=eq.${user.id}`,
        },
        (payload) => {
          setProfile((prev) => ({
            ...prev,
            ...payload.new,
          }));
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.id]);

  /* SEARCH */
  const filtered = useMemo(() => {
    return (sessions || []).filter((s) =>
      (s.title || "New Chat")
        .toLowerCase()
        .includes(search.toLowerCase())
    );
  }, [sessions, search]);

  /* INITIALS */
  const initials = useMemo(() => {
    if (!user?.email) return "U";

    const base = user.email.split("@")[0];
    const parts = base.split(/[._-]/).filter(Boolean);

    return (
      ((parts[0]?.[0] || "") + (parts[1]?.[0] || "") || "U")
    ).toUpperCase();
  }, [user]);

  /* LOGOUT */
  const logout = async () => {
    await supabase.auth.signOut();
    window.location.href = "/";
  };

  /* =========================
     FIXED NEW CHAT
  ========================= */
  const handleNewChat = async () => {
    if (!user?.id) return;

    const { data, error } = await supabase
      .from("chat_sessions")
      .insert([
        {
          user_id: user.id,
          title: "New Chat",
        },
      ])
      .select()
      .single();

    if (error) {
      console.error(error);
      return;
    }

    if (refreshSessions) {
      await refreshSessions();
    }

    setTimeout(() => {
      setActiveChat(data.id);
    }, 50);
  };

  /* AI AVATAR */
  const generateAIAvatar = async () => {
    if (!user?.id) return;

    const url = `https://api.dicebear.com/7.x/adventurer/svg?seed=${user.id}&t=${Date.now()}`;

    const { error } = await supabase
      .from("profiles")
      .update({
        avatar_url: url,
        updated_at: new Date().toISOString(),
      })
      .eq("id", user.id);

    if (error) console.error(error);

    setProfile((prev) => ({
      ...prev,
      avatar_url: url,
    }));
  };

   return (
    <div
      className={`h-full bg-black border-r border-zinc-800 flex flex-col ${
        collapsed ? "w-20" : "w-72"
      }`}
    >

      {/* HEADER */}
      <div className="p-4 flex items-center justify-between border-b border-zinc-800">
        {!collapsed && (
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-md overflow-hidden flex items-center justify-center bg-zinc-900">
              <img
                src="/logo.png"
                alt="ReuNexus Logo"
                className="w-full h-full object-cover"
              />
            </div>

            <div>
              <h1 className="text-white font-bold">ReuNexus</h1>
              <p className="text-xs text-zinc-500">
                {workspace?.name || "Workspace"}
              </p>
            </div>
          </div>
        )}

        <button
          onClick={() => setCollapsed(!collapsed)}
          className="text-zinc-400"
        >
          {collapsed ? "➜" : "⬅"}
        </button>
      </div>

      {/* SEARCH */}
      {!collapsed && (
        <div className="p-3">
          <input
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            placeholder="Search chats..."
            className="w-full bg-zinc-900 text-white p-2 rounded-lg text-sm"
          />
        </div>
      )}

      {/* NEW CHAT */}
      <div className="px-3 mb-2">
        <button
          onClick={handleNewChat}
          className="w-full bg-emerald-400 text-black py-2 rounded-lg text-sm font-bold"
        >
          + {!collapsed && "New Chat"}
        </button>
      </div>

      {/* CHAT LIST */}
      <div className="flex-1 overflow-y-auto p-2 space-y-1">
        {filtered.map((s) => (
          <div
            key={s.id}
            className={`p-2 text-sm rounded cursor-pointer ${
              activeChat === s.id
                ? "bg-zinc-800 text-white"
                : "text-zinc-400 hover:bg-zinc-900"
            }`}
            onClick={() => {
              if (!s?.id) return;
              setActiveChat(String(s.id));
            }}
          >
            {!collapsed && s.title}
          </div>
        ))}
      </div>

      {/* FOOTER */}
      <div className="border-t border-zinc-800 p-3 relative">
        <button
          onClick={() => setAccountOpen(!accountOpen)}
          className="flex items-center gap-2 w-full p-2 hover:bg-zinc-900 rounded-lg"
        >
          <div className="w-8 h-8 rounded-full overflow-hidden bg-zinc-800 flex items-center justify-center">
            {profile?.avatar_url ? (
              <img
                src={profile.avatar_url}
                className="w-full h-full object-cover"
              />
            ) : (
              <span className="text-xs font-bold text-black bg-emerald-400 w-full h-full flex items-center justify-center">
                {initials}
              </span>
            )}
          </div>

          {!collapsed && (
            <span className="text-white text-sm">
              {profile?.display_name || user?.email?.split("@")[0]}
            </span>
          )}
        </button>

        {/* ACCOUNT MENU */}
        <AnimatePresence>
          {accountOpen && (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: 10 }}
              className="absolute bottom-16 left-2 right-2 bg-zinc-950 border border-zinc-800 rounded-xl z-[1000]"
            >
              <MenuItem label="Profile" onClick={() => setProfileOpen(true)} />
              <MenuItem label="Generate AI Avatar" onClick={generateAIAvatar} />
              <MenuItem label="Settings" onClick={() => navigate("/settings")} />
              <MenuItem label="Logout" danger onClick={logout} />
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* PROFILE MODAL */}
      <AnimatePresence>
        {profileOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 bg-black/70 flex items-center justify-center z-[9999]"
            onClick={(e) => {
              if (e.target === e.currentTarget) setProfileOpen(false);
            }}
          >
            <div className="bg-zinc-950 border border-zinc-800 rounded-xl w-[500px] p-4 text-white">
              <h2 className="text-xl font-bold mb-4">Profile</h2>
              <Profile user={user} />
            </div>
          </motion.div>
        )}
      </AnimatePresence>

    </div>
  );
}

/* =========================
   MENU ITEM (FIXED)
========================= */
function MenuItem({ label, onClick, danger }) {
  return (
    <button
      onClick={onClick}
      className={`w-full text-left px-4 py-2 text-sm hover:bg-zinc-900 ${
        danger ? "text-red-400" : "text-zinc-300"
      }`}
    >
      {label}
    </button>
  );
}